INSERT INTO learning_courses (id, title, desc, type, type_label, progress, time_left, image, action, color, btn_color, points, category, content, created_at, updated_at) VALUES (1, '如何使用手机申领医保报销', '手把手教您在手机上操作，简单又省时', 'video', '视频课', 80, '2 分钟', 'https://picsum.photos/seed/course1/800/400', '继续学习', 'bg-black/60', 'bg-blue-500 text-white', 50, '医疗', '本节课程将详细演示如何通过官方APP或微信小程序，在线提交医疗报销凭证。无需线下排队，只需准备好发票、病历等材料的照片，跟着视频一步步操作即可完成申领。', '2026-02-23T11:26:45.152Z', '2026-02-23T11:26:45.152Z') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, progress = EXCLUDED.progress, updated_at = EXCLUDED.updated_at;
INSERT INTO learning_courses (id, title, desc, type, type_label, progress, time_left, image, action, color, btn_color, points, category, content, created_at, updated_at) VALUES (2, '三分钟看懂您的保单保障', '用通俗易懂的漫画带您理清保障范围', 'comic', '趣味漫画', 0, '约 3 分钟', 'https://picsum.photos/seed/course2/800/400', '开始学习', 'bg-blue-500', 'bg-blue-50 text-blue-600', 30, '理赔', '买完保险却不知道保什么？这篇漫画用生动的场景和比喻，帮您快速看懂保单中的核心条款：重疾险保哪些病？医疗险怎么报销？意外险包含哪些意外？让您的保单不再是天书。', '2026-02-23T11:26:45.152Z', '2026-02-23T11:26:45.152Z') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, progress = EXCLUDED.progress, updated_at = EXCLUDED.updated_at;
INSERT INTO learning_courses (id, title, desc, type, type_label, progress, time_left, image, action, color, btn_color, points, category, content, created_at, updated_at) VALUES (3, '2024养老金调整政策解读', '为您划重点，看看每月能多领多少钱', 'article', '实用图文', 45, '剩 5 分钟', 'https://picsum.photos/seed/course3/800/400', '继续阅读', 'bg-slate-800', 'bg-blue-500 text-white', 20, '养老', '2024年国家基本养老金上调政策正式发布。本次调整采取定额调整、挂钩调整与适当倾斜相结合的办法。本文将为您详细解读调整比例、计算方法以及高龄退休人员的特殊倾斜政策。', '2026-02-23T11:26:45.152Z', '2026-02-23T11:26:45.152Z') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, progress = EXCLUDED.progress, updated_at = EXCLUDED.updated_at;
